def safe_tool_chain(claude_response):
    for content in claude_response.content:
        if content.type == 'tool_use':
            tool_result = execute_tool(content)

            # Verify before next tool call
            if 'code' in tool_result:
                verified = verify(
                    code=tool_result['code'],
